export default function OlimpiadasSeedPage({ onBack }) {
  const [status, setStatus] = useState("");
  const [done, setDone] = useState(false);
  const [modo, setModo] = useState("update"); // "update" | "insert"

  const executarUpdate = async () => {
    if (!window.confirm("Atualizar CREDE e Município dos " + SEED_DATA.length + " registros no Firebase?")) return;
    setStatus("Buscando registros existentes...");
    try {
      const snap = await getDocs(collection(db, "olimpiadas_escolas"));
      const existentes = snap.docs.map(d => ({ firestoreId: d.id, ...d.data() }));
      
      let atualizados = 0, naoEncontrados = 0;
      
      for (let i = 0; i < SEED_DATA.length; i++) {
        const r = SEED_DATA[i];
        // Find matching record by edicao + nomeEscola
        const match = existentes.find(e => 
          e.edicao === r.edicao && 
          e.nomeEscola && r.nomeEscola &&
          e.nomeEscola.trim().toUpperCase() === r.nomeEscola.trim().toUpperCase()
        );
        
        if (match) {
          await updateDoc(doc(db, "olimpiadas_escolas", match.firestoreId), {
            crede: r.crede || match.crede || "",
            municipio: r.municipio || match.municipio || "",
          });
          atualizados++;
        } else {
          naoEncontrados++;
        }
        
        if ((i + 1) % 10 === 0) {
          setStatus("Processados: " + (i+1) + "/" + SEED_DATA.length + " | Atualizados: " + atualizados);
        }
      }
      
      setStatus("✅ Concluído! " + atualizados + " atualizados | " + naoEncontrados + " não encontrados");
      setDone(true);
    } catch(e) {
      setStatus("❌ Erro: " + e.message);
    }
  };

  const executarInsert = async () => {
    if (!window.confirm("Inserir " + SEED_DATA.length + " registros novos no Firebase?")) return;
    setStatus("Inserindo registros...");
    try {
      let count = 0;
      for (let i = 0; i < SEED_DATA.length; i++) {
        await addDoc(collection(db, "olimpiadas_escolas"), SEED_DATA[i]);
        count++;
        if (count % 10 === 0) setStatus("Inseridos: " + count + "/" + SEED_DATA.length);
      }
      setStatus("✅ " + SEED_DATA.length + " registros inseridos!");
      setDone(true);
    } catch(e) {
      setStatus("❌ Erro: " + e.message);
    }
  };

  return (
    <div style={{ minHeight:"100vh", background:"#f0f2f5", fontFamily:"'Montserrat',sans-serif", display:"flex", alignItems:"center", justifyContent:"center", padding:24 }}>
      <div style={{ background:"#fff", borderRadius:24, padding:40, maxWidth:520, width:"100%", boxShadow:"0 4px 24px rgba(27,63,122,0.1)" }}>
        <div style={{ textAlign:"center", marginBottom:24 }}>
          <div style={{ fontSize:48, marginBottom:12 }}>🏆</div>
          <div style={{ fontWeight:900, fontSize:22, color:"#1B3F7A", marginBottom:8 }}>Seed Olímpiadas</div>
          <div style={{ color:"#888", fontSize:13 }}>{SEED_DATA.length} registros com CREDE e Município</div>
        </div>

        <div style={{ display:"flex", gap:8, marginBottom:20 }}>
          {[
            { v:"update", l:"🔄 Atualizar existentes", desc:"Atualiza CREDE e Município dos registros já cadastrados" },
            { v:"insert", l:"➕ Inserir novos", desc:"Insere como registros novos (use se banco estiver vazio)" },
          ].map(m => (
            <div key={m.v} onClick={() => setModo(m.v)}
              style={{ flex:1, padding:"12px 14px", borderRadius:12, cursor:"pointer", textAlign:"center",
                background: modo===m.v ? "#1B3F7A" : "#f0f4ff",
                color: modo===m.v ? "#fff" : "#555",
                border: modo===m.v ? "none" : "1px solid #e8edf2" }}>
              <div style={{ fontWeight:700, fontSize:12 }}>{m.l}</div>
              <div style={{ fontSize:10, marginTop:4, opacity:0.8 }}>{m.desc}</div>
            </div>
          ))}
        </div>

        <div style={{ background:"#f8f9fb", borderRadius:12, padding:"12px 16px", fontSize:12, color:"#555", marginBottom:20 }}>
          {modo === "update"
            ? "🔄 Busca cada escola no Firebase pelo nome + edição e atualiza os campos CREDE e Município."
            : "➕ Insere todos como registros novos. Use apenas se o banco estiver vazio ou quiser duplicar."}
        </div>

        {status && (
          <div style={{ background:"#f0f9ff", borderRadius:12, padding:"12px 16px", fontSize:13, color:"#0891b2", marginBottom:16, fontWeight:600 }}>
            {status}
          </div>
        )}

        {!done ? (
          <div onClick={modo === "update" ? executarUpdate : executarInsert}
            style={{ background:"#1B3F7A", borderRadius:14, padding:"14px 32px", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", textAlign:"center" }}>
            {modo === "update" ? "🔄 Executar Update" : "🚀 Executar Insert"}
          </div>
        ) : (
          <div onClick={onBack}
            style={{ background:"#059669", borderRadius:14, padding:"14px 32px", color:"#fff", fontWeight:700, fontSize:14, cursor:"pointer", textAlign:"center" }}>
            ✅ Voltar ao Módulo
          </div>
        )}

        <div onClick={onBack} style={{ marginTop:14, fontSize:12, color:"#888", cursor:"pointer", textAlign:"center" }}>← Voltar</div>
      </div>
    </div>
  );
}
